class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedSchemes = ["https"]
    private let allowedPaths = ["/reset-password"]
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard validateURL(url) else {
            print("Invalid URL: \(url)")
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("Failed to parse URL components")
            return false
        }
        
        guard let host = components.host?.lowercased(),
              allowedHosts.contains(host) else {
            print("Invalid or disallowed host")
            return false
        }
        
        guard let scheme = components.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            print("Invalid or disallowed scheme")
            return false
        }
        
        let path = components.path
        guard allowedPaths.contains(path) else {
            print("Invalid or disallowed path")
            return false
        }
        
        switch path {
        case "/reset-password":
            return handlePasswordReset(components: components)
        default:
            return false
        }
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard url.scheme != nil,
              url.host != nil else {
            return false
        }
        return true
    }
    
    private func handlePasswordReset(components: URLComponents) -> Bool {
        guard let queryItems = components.queryItems else {
            print("No query parameters found")
            return false
        }
        
        guard let tokenItem = queryItems.first(where: { $0.name == "token" }),
              let token = tokenItem.value else {
            print("Token parameter missing or invalid")
            return false
        }
        
        guard validateResetToken(token) else {
            print("Token validation failed")
            return false
        }
        
        DispatchQueue.main.async {
            self.navigateToPasswordReset(token: token)
        }
        
        return true
    }
    
    private func validateResetToken(_ token: String) -> Bool {
        let tokenPattern = "^[a-zA-Z0-9_-]{32,128}$"
        let tokenPredicate = NSPredicate(format: "SELF MATCHES %@", tokenPattern)
        
        guard tokenPredicate.evaluate(with: token) else {
            print("Token format validation failed")
            return false
        }
        
        guard token.count >= 32 && token.count <= 128 else {
            print("Token length validation failed")
            return false
        }
        
        let allowedCharacterSet = CharacterSet(charactersIn: "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-")
        guard token.rangeOfCharacter(from: allowedCharacterSet.inverted) == nil else {
            print("Token contains invalid characters")
            return false
        }
        
        return true
    }
    
    private func navigateToPasswordReset(token: String) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let passwordResetVC = PasswordResetViewController(token: token)
        
        if let navigationController = rootViewController as? UINavigationController {
            navigationController.pushViewController(passwordResetVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
