        let digitPattern = ".*[0-9]+.*"
        let specialCharPattern = ".*[!@#$%^&*()_+\\-=\\[\\]{};':\"\\\\|,.<>\\/?]+.*"
        
        let uppercasePredicate = NSPredicate(format: "SELF MATCHES %@", uppercasePattern)
